module pitch_detection(  
    input clk,  
    input rst,  
    input [7:0] pitch_input,  
    output reg pitch_detected  
);  
    parameter THRESHOLD = 8'd128;  

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin  
        if (rst) begin  
            pitch_detected <= 0;  
        end else begin  
            if (pitch_input > THRESHOLD)  
                pitch_detected <= 1;  
            else  
                pitch_detected <= 0;  
        end  
    end  
endmodule
